public struct PodcastDispatchOutcome {
    public var correlationId: String?
    public var error: String?
    public var code: String?

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(correlationId: String?, error: String?, code: String?) {
        self.correlationId = correlationId
        self.error = error
        self.code = code
    }
}

#if compiler(>=6)
extension PodcastDispatchOutcome: Sendable {}
#endif


extension PodcastDispatchOutcome: Equatable, Hashable {
    public static func ==(lhs: PodcastDispatchOutcome, rhs: PodcastDispatchOutcome) -> Bool {
        if lhs.correlationId != rhs.correlationId {
            return false
        }
        if lhs.error != rhs.error {
            return false
        }
        if lhs.code != rhs.code {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(correlationId)
        hasher.combine(error)
        hasher.combine(code)
    }
}



